// GuaranteedCommitmentsServer is the server API for GuaranteedCommitments service.
// All implementations must embed UnimplementedGuaranteedCommitmentsServer
// for forward compatibility
//
// GuaranteedCommitments service definition.
type GuaranteedCommitmentsServer interface {
	// WORK-IN-PROGRESS: List all the registered orgs
	ListOrgs(*ListOrgsRequest, GuaranteedCommitments_ListOrgsServer) error
	// WORK-IN-PROGRESS: Executes a commitment purchase plan, initiating the commitment purchase process.
	CommitmentsPlanApply(context.Context, *CommitmentPlanApplyRequest) (*CommitmentPlanDetails, error)
	// WORK-IN-PROGRESS: Retrieves a list of commitments.
	ListCommitments(context.Context, *ListCommitmentsRequest) (*ListCommitmentsResponse, error)
	// WORK-IN-PROGRESS: Generates time-series chart data for commitment metrics over the specified time period.
	GetCommitmentsChart(context.Context, *GetCommitmentsChartRequest) (*CommitmentsChartResponse, error)
	// WORK-IN-PROGRESS: Generates utilization data for commitment over the active period.
	GetCommitmentsUtilization(context.Context, *GetCommitmentsUtilizationRequest) (*CommitmentsUtilizationResponse, error)
	// WORK-IN-PROGRESS: Do not use. Retrieves key performance metrics for cloud commitments.
	GetMetrics(context.Context, *GetMetricsRequest) (*MetricsResponse, error)
	// WORK-IN-PROGRESS: Do not use. Retrieves a list of infrastructure resources for the organization.
	ListResources(context.Context, *ListResourcesRequest) (*ListResourcesResponse, error)
	// WORK-IN-PROGRESS: Do not use. Retrieves daily usage data for a specific resource within the specified date range.
	GetResourceDailyUsage(context.Context, *GetResourceDailyUsageRequest) (*GetResourceDailyUsageResponse, error)
	// WORK-IN-PROGRESS: Only works for Alphaus for now. Retrieves a paginated list of reservable infrastructure resources for a segment.
	// Supports filtering, sorting, and a date range for usage aggregation.
	ListReservableResources(context.Context, *ListReservableResourcesRequest) (*ListReservableResourcesResponse, error)
	// WORK-IN-PROGRESS: Retrieves purchase plan of a company.
	ListPurchasePlansBySegment(context.Context, *ListPurchasePlansBySegmentRequest) (*ListPurchasePlansBySegmentResponse, error)
	// WORK-IN-PROGRESS: Get the updated details of the plan after the apply plan.
	GetUpdatedPurchasePlansBySegment(context.Context, *GetUpdatedPurchasePlansBySegmentRequest) (*GetUpdatedPurchasePlansBySegmentResponse, error)
	// WORK-IN-PROGRESS: Retrieves full details of a specific purchase plan of a company.
	// Includes the basic info, detailed metrics, commitment line items, covered infrastructure resource matches, and audit history.
	GetPurchasePlansDetails(context.Context, *GetPurchasePlansDetailsRequest) (*GetPurchasePlansDetailsResponse, error)
	// WORK-IN-PROGRESS: Saves a commitment purchase plan as draft.
	SaveCommitmentsPlanAsDraft(context.Context, *SaveCommitmentsPlanAsDraftRequest) (*DefaultPurchasePlan, error)
	// WORK-IN-PROGRESS: Retrieves the drafted purchase plans
	ListDraftPurchasePlans(context.Context, *ListDraftPurchasePlansRequest) (*ListDraftPurchasePlansResponse, error)
	// WORK-IN-PROGRESS: Deletes a drafted purchase plan.
	DeleteDraftPurchasePlan(context.Context, *DeleteDraftPurchasePlanRequest) (*DeleteDraftPurchasePlanResponse, error)
	// WORK-IN-PROGRESS: Only works for Alphaus for now. Retrieves the available commitment types for a given provider.
	GetAvailableCommitmentTypes(context.Context, *GetAvailableCommitmentTypesRequest) (*GetAvailableCommitmentTypesResponse, error)
	// WORK-IN-PROGRESS: Only works for Alphaus for now. Creates a custom (top-down) commitment purchase plan.
	CreateCustomCommitmentPlan(context.Context, *CreateCustomCommitmentPlanRequest) (*DefaultPurchasePlan, error)
	// WORK-IN-PROGRESS: Registers a new child organization under the channel partner.
	// Creates the organization, sets up user memberships, and establishes the partnership relationship.
	RegisterOrg(context.Context, *RegisterOrgRequest) (*RegisterOrgResponse, error)
	// WORK-IN-PROGRESS: Starts the onboarding process for an organization.
	// Creates or retrieves an onboarding record and sets the provider to AWS.
	StartAwsOnboarding(context.Context, *StartAwsOnboardingRequest) (*StartAwsOnboardingResponse, error)
	// WORK-IN-PROGRESS: Generates CloudFormation template for AWS integration.
	// Creates the necessary IAM role and policy template for setting up AWS access.
	GetAwsCloudFormationTemplate(context.Context, *GetAwsCloudFormationTemplateRequest) (*GetAwsCloudFormationTemplateResponse, error)
	// WORK-IN-PROGRESS: Generates AWS CloudFormation launch stack URL.
	// Creates a pre-configured URL to deploy the CloudFormation stack in the AWS console.
	GetAwsLaunchStackUrl(context.Context, *GetAwsLaunchStackUrlRequest) (*GetAwsLaunchStackUrlResponse, error)
	// WORK-IN-PROGRESS: Runs AWS onboarding verification process.
	// Creates a new CUR or uses an existing CUR and verifies AWS integration setup
	// and returns validation status for all required features.
	VerifyAwsOnboarding(context.Context, *VerifyAwsOnboardingRequest) (*VerifyAwsOnboardingResponse, error)
	// WORK-IN-PROGRESS: Retrieves the latest onboarding status for:
	// - an MSP
	// - a company under an MSP
	// - a payer account under an MSP
	GetOnboardingStatus(context.Context, *GetOnboardingStatusRequest) (*GetOnboardingStatusResponse, error)
	// WORK-IN-PROGRESS: Lists payer accounts associated with the organization.
	// Retrieves all payer accounts linked to the organization, including their status and associated segments.
	ListPayerAccounts(context.Context, *ListPayerAccountsRequest) (*ListPayerAccountsResponse, error)
	SetPayerAccountEnabled(context.Context, *SetPayerAccountEnabledRequest) (*SetPayerAccountEnabledResponse, error)
	GetPayerAccountStatus(context.Context, *GetPayerAccountStatusRequest) (*GetPayerAccountStatusResponse, error)
	ListBillingGroups(context.Context, *ListBillingGroupsRequest) (*ListBillingGroupsResponse, error)
	SetBillingGroupStatus(context.Context, *SetBillingGroupStatusRequest) (*SetBillingGroupStatusResponse, error)
	GetBillingGroupStatus(context.Context, *GetBillingGroupStatusRequest) (*GetBillingGroupStatusResponse, error)
	ValidateBillingGroup(context.Context, *ValidateBillingGroupRequest) (*ValidateBillingGroupResponse, error)
	// Retrieves the AWS Marketplace private offer details for a payer account.
	// Used by the onboarding "Accept Private Offer" step.
	GetAwsPrivateOffer(context.Context, *GetAwsPrivateOfferRequest) (*GetAwsPrivateOfferResponse, error)
	// GetGuaranteedCommitmentTemplateUrl returns a CloudFormation launch URL for deploying
	// both Alphaus (Ripple) and Archera IAM roles in a single stack.
	GetGuaranteedCommitmentTemplateUrl(context.Context, *GetGuaranteedCommitmentTemplateUrlRequest) (*GetGuaranteedCommitmentTemplateUrlResponse, error)
	// CreateGuaranteedCommitmentAccess verifies and registers a deployed guaranteed CloudFormation stack.
	CreateGuaranteedCommitmentAccess(context.Context, *CreateGuaranteedCommitmentAccessRequest) (*CreateGuaranteedCommitmentAccessResponse, error)
	// WORK-IN-PROGRESS: Starts the Azure onboarding process.
	// Creates an onboarding record in Archera for the given org and returns the onboardingId.
	// Stores the Ripple billingGroupId/companyId association for later use.
	StartAzureOnboarding(context.Context, *StartAzureOnboardingRequest) (*StartAzureOnboardingResponse, error)
	// WORK-IN-PROGRESS: Updates the Azure onboarding record.
	UpdateAzureOnboarding(context.Context, *UpdateAzureOnboardingRequest) (*AzureOnboardingState, error)
	// WORK-IN-PROGRESS: Returns the Azure OAuth URL the user must visit to authorize Archera.
	GetAzureOnboardingAuthUrl(context.Context, *GetAzureOnboardingAuthUrlRequest) (*GetAzureOnboardingAuthUrlResponse, error)
	// WORK-IN-PROGRESS: Validates that the Azure app was installed and the user authorized it.
	ValidateAzureAppInstall(context.Context, *ValidateAzureAppInstallRequest) (*AzureOnboardingState, error)
	// WORK-IN-PROGRESS: Lists the available Azure subscriptions or billing accounts
	// for the user to select during onboarding.
	ListAzureOnboardingAccounts(context.Context, *ListAzureOnboardingAccountsRequest) (*ListAzureOnboardingAccountsResponse, error)
	// WORK-IN-PROGRESS: Creates the Azure cloud integration after all onboarding steps complete.
	CreateAzureIntegration(context.Context, *CreateAzureIntegrationRequest) (*CreateAzureIntegrationResponse, error)
	// WORK-IN-PROGRESS: Lists Azure integrations to verify onboarding completion.
	ListAzureIntegrations(context.Context, *ListAzureIntegrationsRequest) (*ListAzureIntegrationsResponse, error)
	mustEmbedUnimplementedGuaranteedCommitmentsServer()
}

